import{_ as e,c as a,a1 as i,o as r}from"./chunks/framework.BDxlaA_J.js";const u=JSON.parse(`{"title":"Identify Target System's OS with TTL (Time-to-Live) and TCP Windows Sizes using Wireshark","description":"","frontmatter":{},"headers":[],"relativePath":"categories/ethical-hacking-labs/2-scanning-networks/2-TTL.md","filePath":"categories/ethical-hacking-labs/2-scanning-networks/2-TTL.md"}`),n={name:"categories/ethical-hacking-labs/2-scanning-networks/2-TTL.md"};function s(o,t,d,c,h,l){return r(),a("div",null,t[0]||(t[0]=[i('<h1 id="identify-target-system-s-os-with-ttl-time-to-live-and-tcp-windows-sizes-using-wireshark" tabindex="-1">Identify Target System&#39;s OS with TTL (Time-to-Live) and TCP Windows Sizes using Wireshark <a class="header-anchor" href="#identify-target-system-s-os-with-ttl-time-to-live-and-tcp-windows-sizes-using-wireshark" aria-label="Permalink to &quot;Identify Target System&#39;s OS with TTL (Time-to-Live) and TCP Windows Sizes using Wireshark&quot;">​</a></h1><p>Identifying the OS used on the target host allows an attacker to figure out the vulnerabilities the system have and the exploits that might work on a system to further perform additional attacks.</p><p>Capture the response generated from the target machine using packet-sniffing tools such as Wireshark and watch the TTL and TCP window size.</p><h3 id="objectives" tabindex="-1">Objectives: <a class="header-anchor" href="#objectives" aria-label="Permalink to &quot;Objectives:&quot;">​</a></h3><ul><li>Identify OS&#39;s by TTL and TCP window size using Wireshark.</li></ul><h3 id="requirements" tabindex="-1">Requirements: <a class="header-anchor" href="#requirements" aria-label="Permalink to &quot;Requirements:&quot;">​</a></h3><ul><li>Linux Ubuntu machine.</li><li>Windows 7 machine.</li><li>Windows 10 machine (Target running Wireshark).</li></ul><h2 id="overview-of-banner-grabbing" tabindex="-1">Overview of Banner Grabbing: <a class="header-anchor" href="#overview-of-banner-grabbing" aria-label="Permalink to &quot;Overview of Banner Grabbing:&quot;">​</a></h2><p><strong>There are two types of banner grabbing techniques: active and passive.</strong></p><p>Banner grabbing or OS fingerprinting is the method to determine the OS running on a remote target system.</p><table tabindex="0"><thead><tr><th>Operating System</th><th>Time-to-Live(TTL)</th><th>TCP Window Size</th></tr></thead><tbody><tr><td>Linux(Kernel 2.4 and 2.6)</td><td>64</td><td>5840</td></tr><tr><td>FreeBSD</td><td>64</td><td>65535</td></tr><tr><td>OpenBSD</td><td>64</td><td>65535</td></tr><tr><td>Google customized Linux</td><td>64</td><td>5720</td></tr><tr><td>Windows XP</td><td>128</td><td>65535</td></tr><tr><td>Windows 7, Vista and Server 2008</td><td>128</td><td>8192</td></tr><tr><td>Cisco Router IOS 12.4</td><td>255</td><td>4128</td></tr></tbody></table><h2 id="using-wireshark-to-detect-ttl" tabindex="-1">Using Wireshark to Detect TTL <a class="header-anchor" href="#using-wireshark-to-detect-ttl" aria-label="Permalink to &quot;Using Wireshark to Detect TTL&quot;">​</a></h2><ol><li>Open Wireshark on your Windows 10 machine, select the correct interface and start capturing. (The interface may differ from your lab environment).</li></ol><p><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/c68b799fcf3e60f75c0111fbcee309cd630def61/start-wireshark-1.png" alt="Wireshark Start" title="Wireshark Start!"></p><ol start="2"><li>Go to the Ubuntu machine and start pinging the Windows 10 machine.</li></ol><p><code>ping -c 10 &lt;Target IP Address[Windows 10]&gt;</code></p><p><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/c68b799fcf3e60f75c0111fbcee309cd630def61/ping-ubuntu-2.png" alt="Ubuntu Ping" title="Ubuntu Ping"></p><ol start="3"><li>Go back to the Wireshark and inspect the ICMP protocol by selecting the packet frame captured; Expand the Internet Protocol Version node in the packet details, you will see the TTL.</li></ol><p>TTL value recorded as <code>64</code> means that the ICMP request came from a Linux-based machine.</p><p><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/b191cdf69129f7cfa87ddbaae31340b37c2b1bbc/wireshark-capturing-ubuntu64-3.png" alt="Wireshark Ubuntu Ping" title="Capturing Ubuntu ICMP"></p><ol start="4"><li>Refresh the Wireshark by starting another capture and go to your Windows 7.</li></ol><p>You will repeat the same process, but with the Windows 7 machine. Open the Prompt or Powershell and ping the Windows 10 machine running Wireshark.</p><p><code>ping &lt;Target IP Address&gt;</code></p><ol start="5"><li>Go back to the Wireshark on Windows 10 machine and inspect again the same TTL information.</li></ol><p>TTL value recorded as <code>128</code> means that the ICMP request came from a Windows-based machine.</p><p><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/b191cdf69129f7cfa87ddbaae31340b37c2b1bbc/wireshark-capturing-win7-128-4.png" alt="Wireshark windows ping"></p>',26)]))}const p=e(n,[["render",s]]);export{u as __pageData,p as default};
